parameters.jsCode:
return $input.all().map(item => {
  const texto = item.json.output || '';
  const caracteres = texto.length;

  // Cada caractere → 50ms (20 cps)
  const tempoCalculado = caracteres * 35;

  // Tempo total = 5000 (base) + tempo calculado
  const tempoTotal = 500 + tempoCalculado;

  return {
    json: {
      output: {
        message: texto,
        time_texting: tempoTotal // Mantido como number
      }
    }
  };
});

